    @CurrentUser() user: CurrentUserPayload,
    @Param('id', ParseIntPipe) id: number,
  ) {
    return this.svc.deleteProject(user.companyId!, id);
  }

  // ─── Milestones ───

  @Get(':id/milestones')
  @ApiOperation({ summary: '里程碑列表' })
