}

/* ==================== Page Header ==================== */
.wc-page-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 20px;
}

.wc-page-title {
  font-size: 20px;
  font-weight: 600;
  color: var(--color-text-primary);
  margin: 0;
}

.wc-page-subtitle {
  font-size: 12px;
  color: var(--color-text-tertiary);
  margin-top: 2px;
}

/* ==================== 安全保障区块 ==================== */
.wc-security-box {
  background: var(--color-primary-bg-soft);
  border: 1px solid var(--color-primary-border);
  border-radius: var(--radius-lg);
  padding: 16px 20px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.wc-security-item {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  color: var(--color-text-secondary);
}

.wc-security-icon {
  color: var(--color-primary);
  font-size: 16px;
  flex-shrink: 0;
}

/* ==================== 精致度强化 V1.1 ==================== */

/* ── 按钮全状态精细规范 ── */

/* 通用过渡（所有按钮） */
.ant-btn {
  font-weight: 500 !important;
  letter-spacing: 0.01em !important;
  transition:
    color var(--duration-fast) var(--ease-out),
    background var(--duration-fast) var(--ease-out),
    border-color var(--duration-fast) var(--ease-out),
    box-shadow var(--duration-fast) var(--ease-out),
    opacity var(--duration-fast) var(--ease-out) !important;
}

/* Default（线框按钮）*/
.ant-btn-default {
  border-color: var(--color-border) !important;
  color: var(--color-text-secondary) !important;
}

.ant-btn-default:hover {
  border-color: var(--color-primary-border) !important;
  color: var(--color-primary) !important;
  background: var(--color-primary-bg-soft) !important;
}

.ant-btn-default:active {
  border-color: var(--color-primary) !important;
  color: var(--color-primary-active) !important;
}

/* Primary 微发光效果 */
.ant-btn-primary:not(:disabled):hover {
  box-shadow: 0 4px 12px rgba(8, 88, 244, 0.28) !important;
  transform: translateY(-1px);
}

.ant-btn-primary:active {
  transform: translateY(0) !important;
  box-shadow: none !important;
}

/* Primary Large（登录/注册主按钮） */
.ant-btn-lg.ant-btn-primary {
  font-size: 15px !important;
  font-weight: 600 !important;
  letter-spacing: 0.04em !important;
  border-radius: var(--radius-lg) !important;
  height: 44px !important;
}

/* Default Large（页头操作按钮） */
.ant-btn-lg.ant-btn-default,
.ant-btn-lg:not(.ant-btn-primary):not(.ant-btn-text):not(.ant-btn-link) {
  height: 36px !important;
  font-size: 14px !important;
  border-radius: var(--radius-md) !important;
}

/* Default（表格内、筛选条） */
.ant-btn-default,
.ant-btn:not(.ant-btn-primary):not(.ant-btn-lg):not(.ant-btn-sm):not(.ant-btn-text):not(.ant-btn-link) {
  height: 32px !important;
  border-radius: var(--radius-md) !important;
  font-size: 13px !important;
}

/* Small（标签内、操作列） */
.ant-btn-sm {
  height: 24px !important;
  padding: 0 8px !important;
  font-size: 12px !important;
  border-radius: var(--radius-sm) !important;
}

/* Link 按钮 */
.ant-btn-link {
  color: var(--color-primary) !important;
  font-weight: 400 !important;
  padding: 0 4px !important;
}

.ant-btn-link:hover {
  color: var(--color-primary-hover) !important;
  background: transparent !important;
}

/* Text 按钮 */
.ant-btn-text {
  color: var(--color-text-secondary) !important;
}

.ant-btn-text:hover {
  color: var(--color-text-primary) !important;
  background: var(--color-bg-hover) !important;
}

/* Danger 按钮 */
.ant-btn-dangerous {
  border-color: var(--color-error) !important;
  color: var(--color-error) !important;
}

.ant-btn-dangerous:hover {
  background: var(--color-error-bg) !important;
  border-color: var(--color-error) !important;
}

.ant-btn-dangerous.ant-btn-primary {
  background: var(--color-error) !important;
  color: #fff !important;
}

/* Disabled 状态 */
.ant-btn:disabled,
.ant-btn[disabled] {
  opacity: 0.45 !important;
  cursor: not-allowed !important;
  pointer-events: auto !important;
  transform: none !important;
  box-shadow: none !important;
}

/* 按钮内图标对齐（间距精修） */
.ant-btn > .anticon + span,
.ant-btn > span + .anticon {
  margin-inline-start: 6px !important;
}

.ant-btn-sm > .anticon + span,
.ant-btn-sm > span + .anticon {
  margin-inline-start: 4px !important;
}

/* ── 排版精细规范 ── */

/* 强标题层级 */
.wc-h1 { font-size: 24px; font-weight: 700; color: var(--color-text-primary); line-height: 1.25; letter-spacing: -0.3px; }
.wc-h2 { font-size: 20px; font-weight: 600; color: var(--color-text-primary); line-height: 1.3;  }
.wc-h3 { font-size: 16px; font-weight: 600; color: var(--color-text-primary); line-height: 1.4;  }
.wc-h4 { font-size: 14px; font-weight: 600; color: var(--color-text-primary); line-height: 1.5;  }

/* 正文层级 */
.wc-body-lg { font-size: 15px; color: var(--color-text-secondary); line-height: 1.6; }
.wc-body    { font-size: 14px; color: var(--color-text-secondary); line-height: 1.57; }
.wc-body-sm { font-size: 13px; color: var(--color-text-secondary); line-height: 1.54; }
.wc-caption { font-size: 12px; color: var(--color-text-tertiary);  line-height: 1.5;  }
.wc-label   { font-size: 12px; color: var(--color-text-tertiary); font-weight: 500; letter-spacing: 0.04em; text-transform: uppercase; }

/* ── 输入框精细规范 ── */

/* 统一圆角 */
.ant-input,
.ant-input-affix-wrapper,
.ant-select-selector,
.ant-input-number {
  border-radius: var(--radius-md) !important;
}

/* 输入框 placeholder 颜色 */
.ant-input::placeholder,
.ant-input-password input::placeholder {
  color: var(--color-text-disabled) !important;
  font-size: 13px !important;
}

/* 表单 label 精修 */
.ant-form-item-label > label {
  font-size: 13px !important;
  font-weight: 500 !important;
  color: var(--color-text-secondary) !important;
}

/* required 星号颜色 */
.ant-form-item-required::before {
  color: var(--color-error) !important;
}

/* 表单校验错误文字 */
.ant-form-item-explain-error {
  font-size: 12px !important;
  color: var(--color-error) !important;
}

/* ── 下拉 / Select 精细规范 ── */

.ant-select-selector {
  border-color: var(--color-border) !important;
}

.ant-select:not(.ant-select-disabled):hover .ant-select-selector {
  border-color: var(--color-primary-border) !important;
}

.ant-select-item-option-selected {
  background: var(--color-primary-bg-soft) !important;
  color: var(--color-primary) !important;
  font-weight: 500 !important;
}

.ant-select-item-option-active {
  background: var(--color-bg-hover) !important;
}

/* ── Tooltip 精细规范 ── */

.ant-tooltip-inner {
  background: rgba(24, 24, 24, 0.88) !important;
  border-radius: var(--radius-md) !important;
  font-size: 12px !important;
  padding: 6px 10px !important;
  box-shadow: var(--shadow-md) !important;
}

/* ── Dropdown 精细规范 ── */

.ant-dropdown-menu {
  border-radius: var(--radius-lg) !important;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.12) !important;
  padding: 4px !important;
}

.ant-dropdown-menu-item {
  border-radius: var(--radius-sm) !important;
  font-size: 13px !important;
  color: var(--color-text-secondary) !important;
  transition: background var(--duration-fast) var(--ease-out) !important;
}

.ant-dropdown-menu-item:hover {
  background: var(--color-bg-hover) !important;
  color: var(--color-text-primary) !important;
}

.ant-dropdown-menu-item-danger {
  color: var(--color-error) !important;
}

.ant-dropdown-menu-item-danger:hover {
  background: var(--color-error-bg) !important;
}

/* ── 分页精细规范 ── */

.ant-pagination-item {
  border-radius: var(--radius-sm) !important;
  border-color: var(--color-border) !important;
  font-size: 13px !important;
}

.ant-pagination-item:hover {
  border-color: var(--color-primary) !important;
}

.ant-pagination-item:hover a {
  color: var(--color-primary) !important;
}

.ant-pagination-prev .ant-pagination-item-link,
.ant-pagination-next .ant-pagination-item-link {
  border-radius: var(--radius-sm) !important;
  border-color: var(--color-border) !important;
}

/* ── Spin / Loading 精细规范 ── */

.ant-spin-dot-item {
  background: var(--color-primary) !important;
}

/* ── 空状态统一规范 ── */

.ant-empty-description {
  color: var(--color-text-tertiary) !important;
  font-size: 13px !important;
}

.ant-empty-image {
  height: 48px !important;
}

/* ── Checkbox & Radio 精细规范 ── */

.ant-checkbox-checked .ant-checkbox-inner {
  background: var(--color-primary) !important;
  border-color: var(--color-primary) !important;
}

.ant-checkbox:hover .ant-checkbox-inner,
.ant-checkbox-input:focus + .ant-checkbox-inner {
  border-color: var(--color-primary) !important;
}

.ant-radio-checked .ant-radio-inner {
  border-color: var(--color-primary) !important;
}

.ant-radio-inner::after {
  background: var(--color-primary) !important;
}

/* ── Switch 精细规范 ── */

.ant-switch-checked {
  background: var(--color-primary) !important;
}

/* ── DatePicker 精细规范 ── */

.ant-picker {
  border-radius: var(--radius-md) !important;
  border-color: var(--color-border) !important;
}

.ant-picker:hover {
  border-color: var(--color-primary-border) !important;
}

.ant-picker-focused {
  border-color: var(--color-primary) !important;
  box-shadow: 0 0 0 3px rgba(8, 88, 244, 0.12) !important;
}

.ant-picker-cell-in-view.ant-picker-cell-selected .ant-picker-cell-inner {
  background: var(--color-primary) !important;
  border-radius: var(--radius-sm) !important;
}

.ant-picker-cell-in-view.ant-picker-cell-today .ant-picker-cell-inner::before {
  border-color: var(--color-primary) !important;
  border-radius: var(--radius-sm) !important;
}

.ant-picker-header-view button:hover {
  color: var(--color-primary) !important;
}

/* ── 滚动条精细规范（WebKit） ── */

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--color-border);
  border-radius: 3px;
  transition: background var(--duration-fast);
}

::-webkit-scrollbar-thumb:hover {
  background: var(--color-text-disabled);
}

::-webkit-scrollbar-corner {
  background: transparent;
}

/* ── 焦点环（无障碍） ── */

.ant-btn:focus-visible,
.ant-input:focus-visible,
.ant-select-selector:focus-visible {
  outline: 2px solid var(--color-primary) !important;
  outline-offset: 2px !important;
}

/* ── 图片占位（加载中） ── */

img {
  display: block;
}

img[src=''],
img:not([src]) {
  background: var(--color-bg-hover);
  min-height: 32px;
}

/* ── 选中文本颜色 ── */

::selection {
  background: var(--color-primary-bg);
  color: var(--color-primary);
}

/* ── Number Input 精细规范 ── */

.ant-input-number {
  border-color: var(--color-border) !important;
}

.ant-input-number:hover {
  border-color: var(--color-primary-border) !important;
}

.ant-input-number-focused {
  border-color: var(--color-primary) !important;
  box-shadow: 0 0 0 3px rgba(8, 88, 244, 0.12) !important;
}

/* ── Drawer 精细规范 ── */

.ant-drawer-content {
  border-radius: var(--radius-xl) 0 0 var(--radius-xl) !important;
}

.ant-drawer-header {
  border-bottom: 1px solid var(--color-border-light) !important;
  padding: 16px 20px !important;
}

.ant-drawer-title {
  font-size: 16px !important;
  font-weight: 600 !important;
  color: var(--color-text-primary) !important;
}

/* ── Table 精细规范（补充） ── */

/* 选中行高亮 */
.ant-table-tbody > tr.ant-table-row-selected > td {
  background: var(--color-primary-bg-soft) !important;
}

/* 行hover过渡 */
.ant-table-tbody > tr {
  transition: background var(--duration-fast) var(--ease-out) !important;
}

/* 固定列阴影精修 */
.ant-table-cell-fix-left-last::after,
.ant-table-cell-fix-right-first::before {
  box-shadow: inset -6px 0 8px -4px rgba(0, 0, 0, 0.06) !important;
}

/* 排序图标颜色 */
.ant-table-column-sorter-up.active,
.ant-table-column-sorter-down.active {
  color: var(--color-primary) !important;
}

/* ── Input Number 微调按钮精修 ── */

.ant-input-number-handler:hover .ant-input-number-handler-up-inner,
.ant-input-number-handler:hover .ant-input-number-handler-down-inner {
  color: var(--color-primary) !important;
}

/* ── Modal 精细规范（补充） ── */

.ant-modal-title {
  font-size: 16px !important;
  font-weight: 600 !important;
  color: var(--color-text-primary) !important;
}

.ant-modal-footer {
  border-top: 1px solid var(--color-border-light) !important;
  padding: 12px 20px !important;
}

.ant-modal-close-x {
  color: var(--color-text-tertiary) !important;
  transition: color var(--duration-fast) !important;
}

.ant-modal-close-x:hover {
  color: var(--color-text-primary) !important;
}

/* ── Message / Notification 精细规范 ── */

.ant-message-notice-content {
  border-radius: var(--radius-lg) !important;
  box-shadow: var(--shadow-md) !important;
  font-size: 13px !important;
  padding: 8px 16px !important;
}

.ant-notification-notice {
  border-radius: var(--radius-lg) !important;
  box-shadow: var(--shadow-lg) !important;
}

/* ── Popover / Popconfirm 精细规范 ── */

.ant-popover-inner {
  border-radius: var(--radius-lg) !important;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.12) !important;
  padding: 0 !important;
}

.ant-popover-title {
  font-size: 13px !important;
  font-weight: 600 !important;
  border-bottom: 1px solid var(--color-border-light) !important;
  padding: 10px 16px 8px !important;
}

.ant-popover-inner-content {
  font-size: 13px !important;
  color: var(--color-text-secondary) !important;
  padding: 10px 16px !important;
}

/* ── Segmented（分段控制器） ── */

.ant-segmented {
  background: var(--color-bg-page) !important;
  border-radius: var(--radius-md) !important;
  padding: 2px !important;
}

.ant-segmented-item-selected {
  background: var(--color-bg-card) !important;
  box-shadow: var(--shadow-sm) !important;
  border-radius: var(--radius-sm) !important;
}

.ant-segmented-item-label {
  font-size: 13px !important;
  color: var(--color-text-secondary) !important;
}

.ant-segmented-item-selected .ant-segmented-item-label {
  color: var(--color-text-primary) !important;
  font-weight: 500 !important;
}

/**
 * WeCreator — Apple-inspired Theme Tokens
 * 使用 systemBlue / systemGray 等 iOS 17 + macOS Sonoma 规范色
 *
 * 两套主题：
 *   [data-theme="light"]  默认亮色
 *   [data-theme="dark"]   暗色
 *
 * data-theme 属性由 useTheme composable 写在 <html> 上
 */

/* ==================== 默认 / 亮色 ==================== */
:root,
:root[data-theme="light"] {
  /* 品牌色 — iOS systemBlue */
  --color-primary:          #007AFF;
  --color-primary-hover:    #3395FF;
  --color-primary-active:   #0062CC;
  --color-primary-light:    #4DA2FF;
  --color-primary-lighter:  #99C7FF;
  --color-primary-bg:       #D9EBFF;
  --color-primary-bg-soft:  #E8F2FF;
  --color-primary-border:   #B0D4FF;

  /* 活力橙 — systemOrange */
  --color-accent:       #FF9500;
  --color-accent-light: #FFB340;
  --color-accent-bg:    #FFF2E0;

  /* 语义色 — iOS system */
  --color-success:      #34C759;
  --color-success-bg:   #E4F8E9;
  --color-warning:      #FF9500;
  --color-warning-bg:   #FFF2E0;
  --color-error:        #FF3B30;
  --color-error-bg:     #FFE6E4;
  --color-teal:         #30B0C7;
  --color-teal-bg:      #E0F3F7;
  --color-purple:       #AF52DE;
  --color-purple-bg:    #F3E5FA;

  /* 中性色 — systemGrouped / label 系 */
  --color-text-primary:   #000000;
  --color-text-secondary: rgba(60, 60, 67, 0.60);
  --color-text-tertiary:  rgba(60, 60, 67, 0.40);
  --color-text-disabled:  rgba(60, 60, 67, 0.25);
  --color-text-placeholder: rgba(60, 60, 67, 0.30);
  --color-text-inverse:   #FFFFFF;
  --color-border:         #D1D1D6;
  --color-border-light:   #E5E5EA;
  --color-border-strong:  #AEAEB2;

  --color-bg-page:        #F2F2F7;  /* systemGroupedBackground */
  --color-bg-card:        #FFFFFF;  /* secondarySystemGroupedBackground */
  --color-bg-card-2:      #F2F2F7;  /* tertiarySystemGroupedBackground */
  --color-bg-hover:       #F2F2F7;
  --color-bg-sidebar:     rgba(249, 249, 251, 0.80);
  --color-bg-header:      rgba(255, 255, 255, 0.72);
  --color-bg-mask:        rgba(0, 0, 0, 0.35);
  --color-bg-elevated:    #FFFFFF;  /* 悬浮层如 popover/tooltip */

  /* 任务状态 */
  --status-draft-fg:      rgba(60, 60, 67, 0.60);
  --status-draft-bg:      #E5E5EA;
  --status-matching-fg:   #007AFF;
  --status-matching-bg:   #E8F2FF;
  --status-progress-fg:   #30B0C7;
  --status-progress-bg:   #E0F3F7;
  --status-review-fg:     #FF9500;
  --status-review-bg:     #FFF2E0;
  --status-completed-fg:  #34C759;
  --status-completed-bg:  #E4F8E9;
  --status-closed-fg:     rgba(60, 60, 67, 0.40);
  --status-closed-bg:     #EFEFF4;

  /* 阴影 — Apple 双层叠加（细描边 + 柔和落影） */
  --shadow-sm:   0 1px 2px rgba(0, 0, 0, 0.04),   0 0 0 0.5px rgba(0, 0, 0, 0.06);
  --shadow-md:   0 4px 16px rgba(0, 0, 0, 0.06),  0 0 0 0.5px rgba(0, 0, 0, 0.05);
  --shadow-lg:   0 20px 60px rgba(0, 0, 0, 0.15), 0 0 0 0.5px rgba(0, 0, 0, 0.08);
  --shadow-focus-primary: 0 0 0 4px rgba(0, 122, 255, 0.20);

  /* Vibrancy（毛玻璃） */
  --vibrancy-bg: rgba(255, 255, 255, 0.72);
  --vibrancy-filter: saturate(180%) blur(20px);
}

/* ==================== 暗色 ==================== */
:root[data-theme="dark"] {
  /* 品牌色 — iOS Dark Mode systemBlue（更亮） */
  --color-primary:          #0A84FF;
  --color-primary-hover:    #409CFF;
  --color-primary-active:   #0060D0;
  --color-primary-light:    #409CFF;
  --color-primary-lighter:  #76B3FF;
  --color-primary-bg:       rgba(10, 132, 255, 0.24);
  --color-primary-bg-soft:  rgba(10, 132, 255, 0.16);
  --color-primary-border:   rgba(10, 132, 255, 0.40);

  /* 活力橙 — Dark systemOrange */
  --color-accent:       #FF9F0A;
  --color-accent-light: #FFB340;
  --color-accent-bg:    rgba(255, 159, 10, 0.18);

  /* 语义色 — Dark system */
  --color-success:      #30D158;
  --color-success-bg:   rgba(48, 209, 88, 0.18);
  --color-warning:      #FF9F0A;
  --color-warning-bg:   rgba(255, 159, 10, 0.18);
  --color-error:        #FF453A;
  --color-error-bg:     rgba(255, 69, 58, 0.18);
  --color-teal:         #40C8E0;
  --color-teal-bg:      rgba(64, 200, 224, 0.18);
  --color-purple:       #BF5AF2;
  --color-purple-bg:    rgba(191, 90, 242, 0.18);

  /* 中性色 — 深色 labels */
  --color-text-primary:     #FFFFFF;
  --color-text-secondary:   rgba(235, 235, 245, 0.60);
  --color-text-tertiary:    rgba(235, 235, 245, 0.40);
  --color-text-disabled:    rgba(235, 235, 245, 0.25);
  --color-text-placeholder: rgba(235, 235, 245, 0.30);
  --color-text-inverse:     #000000;
  --color-border:           #38383A;
  --color-border-light:     #2C2C2E;
  --color-border-strong:    #48484A;

  --color-bg-page:          #000000;   /* iOS dark systemGroupedBackground */
  --color-bg-card:          #1C1C1E;   /* secondarySystemBackground */
  --color-bg-card-2:        #2C2C2E;   /* tertiarySystemBackground */
  --color-bg-hover:         #2C2C2E;
  --color-bg-sidebar:       rgba(28, 28, 30, 0.80);
  --color-bg-header:        rgba(28, 28, 30, 0.72);
  --color-bg-mask:          rgba(0, 0, 0, 0.60);
  --color-bg-elevated:      #2C2C2E;

  /* 任务状态 — 暗色 */
  --status-draft-fg:      rgba(235, 235, 245, 0.60);
  --status-draft-bg:      rgba(235, 235, 245, 0.12);
  --status-matching-fg:   #0A84FF;
  --status-matching-bg:   rgba(10, 132, 255, 0.18);
  --status-progress-fg:   #40C8E0;
  --status-progress-bg:   rgba(64, 200, 224, 0.18);
  --status-review-fg:     #FF9F0A;
  --status-review-bg:     rgba(255, 159, 10, 0.18);
  --status-completed-fg:  #30D158;
  --status-completed-bg:  rgba(48, 209, 88, 0.18);
  --status-closed-fg:     rgba(235, 235, 245, 0.40);
  --status-closed-bg:     rgba(235, 235, 245, 0.08);

  /* 阴影 — 深色模式下更深 */
  --shadow-sm:   0 1px 2px rgba(0, 0, 0, 0.40),   0 0 0 0.5px rgba(255, 255, 255, 0.08);
  --shadow-md:   0 4px 16px rgba(0, 0, 0, 0.45),  0 0 0 0.5px rgba(255, 255, 255, 0.06);
  --shadow-lg:   0 20px 60px rgba(0, 0, 0, 0.60), 0 0 0 0.5px rgba(255, 255, 255, 0.08);
  --shadow-focus-primary: 0 0 0 4px rgba(10, 132, 255, 0.30);

  /* Vibrancy（暗色毛玻璃） */
  --vibrancy-bg: rgba(28, 28, 30, 0.72);
  --vibrancy-filter: saturate(180%) blur(20px);
}

/* ==================== 共享令牌（与主题无关） ==================== */
:root {
  /* 间距 — Apple 8pt grid */
  --space-1:  4px;  --space-2: 8px;   --space-3: 12px;
  --space-4: 16px;  --space-5: 20px;  --space-6: 24px;
  --space-8: 32px;  --space-10: 40px; --space-12: 48px;
  --space-16: 64px;

  /* 圆角 — Apple 连续曲率 */
  --radius-sm:   6px;
  --radius-md:  10px;
  --radius-lg:  14px;
  --radius-xl:  20px;
  --radius-2xl: 28px;
  --radius-full: 9999px;

  /* 布局 */
  --layout-header-height:    52px;
  --layout-sider-width:      240px;
  --layout-sider-collapsed:  68px;

  /* 动效 — Apple default curves */
  --ease-out:     cubic-bezier(0.22, 1, 0.36, 1);         /* easeOutExpo 风 */
  --ease-in-out:  cubic-bezier(0.4, 0, 0.6, 1);           /* iOS 默认 */
  --ease-bounce:  cubic-bezier(0.175, 0.885, 0.32, 1.275);
  --duration-fast:    120ms;
  --duration-normal:  240ms;
  --duration-slow:    400ms;

  /* 字体 — SF 栈 */
  --font-family-base:
    -apple-system, BlinkMacSystemFont, "SF Pro Text", "SF Pro Display",
    "Helvetica Neue", "PingFang SC", "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
  --font-family-mono:
    "SF Mono", "Menlo", "Monaco", "Consolas", monospace;
  --font-family-rounded:
    "SF Pro Rounded", -apple-system, BlinkMacSystemFont, sans-serif;
}

edits.newText:
const antTheme = computed(() => {
  const isDark = resolved.value === 'dark'
  return {
    token: isDark ? darkToken : lightToken,
    components: isDark ? darkComponents : lightComponents,
    algorithm: isDark ? antdTheme.darkAlgorithm : antdTheme.defaultAlgorithm,
  }
})

const lightTheme = {
  token: lightToken,
  components: lightComponents,
  algorithm: antdTheme.defaultAlgorithm,
}

// 认证页面强制亮色，其他页面跟随系统主题
const activeTheme = computed(() => isAuthPage.value ? lightTheme : antTheme.value)

// 同步 data-theme 属性：认证页强制 light，其他页面跟随 resolved
watch(
  [isAuthPage, resolved],
  ([auth, theme]) => {
    if (typeof document !== 'undefined') {
      document.documentElement.dataset.theme = auth ? 'light' : theme
      document.documentElement.style.colorScheme = auth ? 'light' : theme
    }
  },
  { immediate: true },
)
</script>

